INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Automatic Contact and Company Enrichment$q$, $q$Scans connected email, calendar, and social accounts to build and continuously update contact and company records without manual entry.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Visual Sales Pipeline$q$, $q$Drag-and-drop deal stages give reps and managers an at-a-glance view of pipeline health across one or more pipelines.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Email and Link Tracking$q$, $q$Automatic notifications when a prospect opens an email, clicks a link, or revisits your website.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$LinkedIn and Email Sidebars$q$, $q$Browser extensions surface CRM context inside Gmail, Outlook, and LinkedIn so reps can log activity without switching tabs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$AI Email Assistant$q$, $q$A built-in AI writing tool drafts and refines emails using CRM account context and the rep's own tone and style.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Workflow Automation$q$, $q$Multi-step email sequences and task automation triggered by pipeline stage or contact activity on higher-tier plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Mobile Apps with Business Card Scanner$q$, $q$iOS and Android apps let reps scan business cards, log visits, and update deals from the field.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Custom Dashboards and Reporting$q$, $q$Configurable dashboards track team activity, pipeline performance, and deal forecasts.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Lead Generation Credits$q$, $q$Monthly credits, varying by plan, for looking up verified contact and company details on new prospects.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Zapier and API Integrations$q$, $q$Connects Salesflare to other business tools through Zapier and a documented API.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Automatic data capture from email, calendar, and social profiles sharply reduces manual CRM data entry.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Clean, fast-to-learn interface with a shorter setup time compared to heavier CRMs.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$No hard limits on contacts, custom fields, or pipelines on any paid plan.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Deep Gmail, Outlook, and LinkedIn integration fits naturally into existing workflows.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Mobile apps with business-card scanning make field and travel use easy.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$No permanent free plan, only a time-limited free trial.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Enterprise tier requires a minimum of five users, which can be restrictive for very small teams.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Less configurable than enterprise CRMs like Salesforce for complex approval or territory structures.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Lead generation credits and advanced automation are gated behind higher-priced tiers.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Limited native localization, with the interface primarily available in English.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Does Salesflare offer a free plan?$q$, $q$No, Salesflare doesn't have a permanent free plan; it offers a 30-day free trial that doesn't require a credit card.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$What does Salesflare cost?$q$, $q$Pricing starts at $29 per user per month billed annually on the Growth plan, rising to $49 for Pro and $99 for Enterprise, which has a five-user minimum.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Which email providers does Salesflare integrate with?$q$, $q$Salesflare integrates directly with Gmail and Outlook, alongside a browser sidebar for LinkedIn and other web pages.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Does Salesflare have a mobile app?$q$, $q$Yes, Salesflare offers iOS and Android apps with features like a business-card scanner for logging contacts in the field.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Is Salesflare suitable for large enterprises?$q$, $q$It's primarily built for small and mid-sized B2B teams; larger organizations needing complex customization or approval workflows may find it too lightweight.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Replacing spreadsheets for a growing sales team$q$, $q$A small B2B team outgrows tracking deals in spreadsheets and adopts Salesflare to get a shared pipeline, automatic contact history, and follow-up reminders without hiring a CRM administrator.$q$, $q$Small B2B sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Agency and consultancy relationship management$q$, $q$Agencies and consultancies use Salesflare to keep track of client and prospect relationships built over long email threads and calls, relying on automatic timeline logging instead of manual notes.$q$, $q$Agencies and consultancies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$LinkedIn-driven prospecting$q$, $q$Reps who source leads through LinkedIn use the browser sidebar to add contacts and companies straight to their pipeline while researching prospects.$q$, $q$B2B sales reps and SDRs$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Field sales and networking events$q$, $q$Reps attending conferences or in-person meetings use the mobile app's business-card scanner to add new contacts to the CRM on the spot rather than re-typing details later.$q$, $q$Field sales representatives$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Growth$q$, $q$$29/user/month$q$, $q$Annual (also available monthly at $39/user)$q$, $q$["Automatic contact and company data enrichment","Email, link, and website-visit tracking","Gmail/Outlook integration and LinkedIn sidebar","iOS and Android mobile apps","Personalized email campaigns","5 lead generation credits per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Pro$q$, $q$$49/user/month$q$, $q$Annual (also available monthly at $64/user)$q$, $q$["Everything in Growth","Multi-step workflow automation","User permission controls","Custom dashboards and reporting","100 lead generation credits per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$Enterprise$q$, $q$$99/user/month$q$, $q$Annual (also available monthly at $124/user); 5-user minimum$q$, $q$["Everything in Pro","Customized onboarding and training","Data migration assistance","Dedicated account manager","250 lead generation credits per month"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Salesflare is a customer relationship management platform built for small and medium-sized B2B companies, founded in 2014 and headquartered in Antwerp, Belgium. Rather than asking sales reps to manually log calls, meetings, and contact details, Salesflare pulls information automatically from email inboxes, calendars, social profiles, and email signatures, then organizes it into a visual pipeline. The goal is to give small sales teams the structure of a CRM without the administrative overhead that usually comes with one.$q$, $q$The product is built around Gmail and Outlook, with browser extensions, a LinkedIn sidebar, and mobile apps for iOS and Android that let reps capture business cards, log visits, and update deals on the go. Email and website-visit tracking show reps who opened a message or revisited a page, while automated follow-up reminders flag deals that have gone quiet, so nothing falls through the cracks between conversations.$q$, $q$Salesflare is often positioned against heavier, more configurable platforms like Salesforce or HubSpot, trading deep customization for a shorter setup time and less day-to-day maintenance. It is a paid product with a time-limited free trial rather than a permanently free tier, and pricing scales per user across three tiers that add automation, permissions, and account management as teams grow. Billing can be monthly or annual, with the annual option reducing the effective per-user rate on every plan.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$who-salesflare-is-for$q$, $q$Who Salesflare Is For$q$, 2, ARRAY[$q$Salesflare is aimed at small and mid-sized B2B teams, typically agencies, consultancies, software vendors, and service businesses, where deals are built on ongoing email and call relationships rather than high-volume transactional sales. Founders and sales leads who want visibility into their pipeline without asking reps to spend time on data entry are a natural fit.$q$, $q$Teams that already live in Gmail or Outlook benefit most, since Salesflare's tracking, contact enrichment, and email sequencing are built around those inboxes rather than as an afterthought. Reps who prospect heavily through LinkedIn also gain from the browser sidebar that surfaces CRM context and lets them add contacts and log activity without leaving the platform.$q$, $q$It also suits growing companies that need a CRM running in days, not months, and that don't have a dedicated RevOps or CRM administrator on staff. Because the core plans have no hard limits on contacts, pipelines, or custom fields, small teams can expand their process over time without hitting artificial ceilings tied to price. Distributed and remote sales teams also tend to fit well, since most of the setup and daily use happens through tools they are already in, such as an email inbox or a phone.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Larger enterprises with complex approval chains, territory management, or deeply customized data models will likely find Salesflare too lightweight; it is built for simplicity rather than the granular configurability of platforms like Salesforce. Organizations that need extensive role hierarchies, custom object relationships, or heavy third-party ecosystem support should look elsewhere.$q$, $q$High-volume, transactional sellers, where deals close in a single low-touch interaction rather than a relationship built over weeks or months, won't get much value from Salesflare's email- and calendar-based automatic data capture, which is designed around longer B2B sales cycles.$q$, $q$Budget-constrained micro teams or solo users who need an indefinitely free tool should also look elsewhere, since Salesflare offers only a time-limited free trial rather than a permanent free plan, and its per-user pricing plus an Enterprise tier with a five-user minimum can add up for teams that don't need the automation it provides. Companies whose sales process depends on strict custom approval workflows or heavily regulated data handling procedures may also need to evaluate whether a lighter-weight CRM like this one can meet those requirements.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Salesflare is automatic data collection: the platform scans connected email accounts, calendars, and social profiles to build and update contact and company records, log meetings, and capture email signatures without manual entry. A visual, drag-and-drop pipeline shows every deal's stage, and built-in reminders nudge reps when a deal has been inactive for a while.$q$, $q$Email and link tracking notify reps when a prospect opens a message or clicks a link, and personalized email campaigns let teams send tracked, templated sequences to segments of contacts. Workflow automation on the higher tiers can trigger multi-step email sequences and task assignments based on pipeline activity, while custom dashboards give managers reporting on team and pipeline performance.$q$, $q$Mobile apps for iOS and Android add a business-card scanner and let reps log visits and calls from the field, and an AI-assisted email composer can draft or refine messages using the CRM's account context and the rep's own writing style. Lead-generation credits, available on every plan, let users look up contact and company details for new prospects directly inside the app, and integrations with Zapier and a documented API extend the platform into other tools a team already relies on.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', $q$the-salesflare-experience$q$, $q$The Salesflare Experience$q$, 2, ARRAY[$q$Users generally describe Salesflare's interface as clean and fast to learn compared with more configuration-heavy CRMs, with most setup happening through connecting an email account rather than building custom objects or fields. The automatic timeline of emails, meetings, and calls attached to each contact is frequently cited as the feature that saves the most day-to-day effort.$q$, $q$Because the CRM leans on integrations, Gmail, Outlook, LinkedIn, Zapier, and a documented API, rather than trying to be an all-in-one suite, day-to-day use tends to feel like an extension of the inbox and calendar reps already use, rather than a separate system they have to update in parallel.$q$, $q$The tradeoff is that teams wanting deep customization, complex multi-stage approval processes, or an extensive built-in app marketplace may find the experience comparatively narrow. For its target audience of small, relationship-driven B2B sales teams, though, the emphasis on automation and a short learning curve is generally the main draw.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('584e1528-a367-458c-a4fb-954e6f1d06c4', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Case Management$q$, $q$Tracks every customer inquiry as a case with full history, assignment rules, priority levels, and SLA-driven escalation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Omnichannel Routing$q$, $q$Distributes incoming cases from email, phone, chat, SMS, and messaging apps to agents based on skill, capacity, or priority.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Knowledge Base$q$, $q$Centralizes troubleshooting articles for agent use and customer self-service, with version control and article recommendations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Einstein AI and Agentforce$q$, $q$Uses AI to classify cases, suggest agent replies, summarize conversations, and autonomously resolve routine requests.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Service Cloud Voice$q$, $q$Brings telephony and call transcription directly into the agent console alongside other channels.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Field Service$q$, $q$Extends case management to dispatched technicians, scheduling, and on-site work orders.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Automation (Macros and Flows)$q$, $q$Lets teams automate repetitive agent actions and business processes without writing code.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Reporting and Dashboards$q$, $q$Provides configurable dashboards for case volume, resolution time, SLA compliance, and agent performance.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Self-Service Communities$q$, $q$Offers branded customer portals where users can search knowledge articles or submit and track cases themselves.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Unified Customer 360 Data$q$, $q$Shares a single customer data model with Sales Cloud and Marketing Cloud so service, sales, and marketing stay aligned.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Deep integration with Sales Cloud and the rest of the Salesforce ecosystem$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Highly configurable case routing, entitlements, and automation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Strong AI capabilities (Einstein and Agentforce) for triage and deflection$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Extensive AppExchange marketplace for prebuilt integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Scales well for large, complex, multi-channel support organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Per-user pricing and add-ons make it expensive relative to simpler helpdesk tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Implementation and configuration typically require dedicated admin or consultant expertise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Steep learning curve for new agents and administrators$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Higher-tier features (Voice, Field Service, advanced AI) require separate paid add-ons$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Overkill for small teams that only need basic ticketing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$What is Salesforce Service Cloud used for?$q$, $q$It's used to manage customer support cases across channels like email, phone, chat, and messaging, with tools for routing, automation, knowledge management, and AI-assisted resolution.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$How much does Salesforce Service Cloud cost?$q$, $q$Pricing starts around $25 per user per month for the Starter Suite tier, billed annually, with higher tiers such as Pro Suite, Enterprise, and Unlimited priced progressively higher based on features and support levels.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Does Salesforce Service Cloud offer a free trial?$q$, $q$Yes, Salesforce typically offers a free trial period so teams can evaluate Service Cloud before committing to a paid plan.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Is Salesforce Service Cloud good for small businesses?$q$, $q$It can be, but its cost and configuration overhead usually make more sense for mid-market and enterprise teams; small businesses with simple support needs may find lighter helpdesk tools more cost-effective.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Does Service Cloud integrate with Salesforce Sales Cloud?$q$, $q$Yes, Service Cloud shares the same underlying Salesforce data model as Sales Cloud and Marketing Cloud, so customer, account, and case data stay unified across teams without separate integration work.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Enterprise Contact Center Consolidation$q$, $q$Unify phone, chat, email, and messaging support into a single console with skills-based routing and SLA tracking.$q$, $q$Enterprise support organizations with high case volume$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$AI-Assisted Case Deflection$q$, $q$Use Einstein and Agentforce to auto-classify incoming cases, suggest replies, and resolve routine requests without agent involvement.$q$, $q$Support teams looking to reduce agent workload at scale$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Field Service Dispatch$q$, $q$Coordinate on-site technician scheduling and work orders tied directly to customer service cases.$q$, $q$Companies with field technicians or on-site service operations$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Unified Sales and Service Data$q$, $q$Give sales and support teams shared visibility into account history, open cases, and customer health.$q$, $q$Organizations already running Salesforce Sales Cloud$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Starter Suite$q$, $q$$25/user/month$q$, $q$Billed annually$q$, $q$["Case management","Email-to-case","Basic knowledge base","Standard reports and dashboards"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Pro Suite$q$, $q$$100/user/month$q$, $q$Billed annually$q$, $q$["Omnichannel routing","Automation with flows","Expanded knowledge base","Service console customization"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Enterprise$q$, $q$$165/user/month$q$, $q$Billed annually$q$, $q$["Advanced case automation","Entitlements and SLA management","Einstein AI features","Deeper customization and API access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$Unlimited$q$, $q$$330/user/month$q$, $q$Billed annually$q$, $q$["Full platform customization","Premier-level support","Advanced AI and automation","Highest API and data limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Salesforce Service Cloud is the customer service arm of the Salesforce platform, built to help support teams manage cases, resolve inquiries across channels, and keep a full history of every customer interaction in one system of record. It sits alongside Sales Cloud and Marketing Cloud as part of Salesforce's Customer 360 vision, sharing the same underlying data model so service, sales, and marketing teams can work from a single view of the customer.$q$, $q$At its core, Service Cloud provides case management, omnichannel routing (email, phone, chat, SMS, and social messaging), a knowledge base for both agents and self-service customers, and workflow automation for repetitive support tasks. Over time Salesforce has layered on Einstein AI and, more recently, Agentforce autonomous agents, which can triage cases, suggest replies, summarize interactions, and in some workflows resolve routine requests without human intervention.$q$, $q$Because it is built on the broader Salesforce platform, Service Cloud inherits the same declarative customization tools (Flow, permission sets, validation rules) and the same AppExchange ecosystem, letting organizations extend it with prebuilt integrations rather than custom code, making it less a standalone helpdesk and more a configurable service layer on top of a company's existing Salesforce data. It has also expanded well beyond a simple email-and-case tool over the years, picking up telephony through Service Cloud Voice, dispatched field technician management through Field Service, and digital engagement channels as native modules rather than bolt-on products. That breadth is part of why larger organizations choose it: a single vendor can cover most of a support operation's channels, though it also means the platform carries more configuration and licensing surface area than a narrowly scoped helpdesk tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$who-salesforce-service-cloud-is-for$q$, $q$Who Salesforce Service Cloud Is For$q$, 2, ARRAY[$q$Service Cloud is best suited to mid-market and enterprise support organizations that already run Sales Cloud or another part of Salesforce and want their support data unified with sales and account history. Companies with complex routing needs — tiered SLAs, multiple business units, or regulated industries requiring detailed audit trails — tend to get the most value from its case assignment rules, entitlements, and escalation logic.$q$, $q$It also fits organizations planning to scale support with automation and AI, since Einstein and Agentforce features are designed to deflect volume from human agents as case counts grow. Teams with dedicated Salesforce administrators or a systems integrator on retainer are in the best position to configure the platform to match their processes, rather than working around a rigid out-of-the-box setup.$q$, $q$Field service organizations, contact centers running Service Cloud Voice, and businesses that need a branded self-service portal or community for customers also find natural fits here, since those capabilities are native add-ons rather than third-party bolt-ons. Regulated industries such as financial services, healthcare, and insurance also gravitate toward Service Cloud because of its granular permissioning, audit trails, and entitlement management, which help demonstrate compliance with support SLAs and data-handling requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Small businesses, solo founders, or lean support teams looking for a quick, low-cost helpdesk should generally look elsewhere. Service Cloud's per-user pricing, implementation overhead, and reliance on admin configuration make it expensive and slow to stand up relative to purpose-built helpdesk tools aimed at small teams.$q$, $q$Organizations without an existing Salesforce footprint or budget for implementation help may also struggle, since Service Cloud is rarely a plug-and-play deployment. Getting routing rules, knowledge articles, and automation configured correctly typically requires either an in-house admin or an outside consultant, adding cost and timeline beyond the license price itself.$q$, $q$Teams that just need simple ticket tracking and basic email support, without a need for omnichannel routing, AI-assisted triage, or deep customization, will likely find Service Cloud more platform than they need, and may be better served by a lighter, purpose-built support tool. Fast-moving startups that prioritize speed of setup over long-term configurability may also find the implementation timeline and admin overhead a poor match for their pace.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Service Cloud's foundation is case management: every customer inquiry becomes a trackable case with a full history, assignment rules, and SLA-driven escalation paths. Omnichannel routing layers on top of this, distributing cases from email, phone, live chat, SMS, and messaging apps to the right agent based on skill, workload, or priority.$q$, $q$The knowledge base lets support teams centralize troubleshooting articles for both internal agent use and customer-facing self-service portals, while Einstein AI and Agentforce add case classification, reply suggestions, conversation summarization, and autonomous resolution of routine requests. Service Cloud Voice brings telephony directly into the same console, and Field Service extends case management to dispatched technicians and on-site work orders.$q$, $q$Automation tools such as macros, flows, and approval processes reduce repetitive agent work, while built-in reporting and dashboards give managers visibility into case volume, resolution time, and agent performance. Because all of this runs on the shared Salesforce data model, service data connects natively to sales and marketing records without separate integration work.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', $q$the-salesforce-service-cloud-experience$q$, $q$The Salesforce Service Cloud Experience$q$, 2, ARRAY[$q$Day to day, agents work inside the Salesforce Lightning Console, a configurable workspace that surfaces case details, customer history, knowledge articles, and macros side by side. The interface is powerful but dense, and new agents typically need onboarding to navigate the console efficiently, especially in orgs with heavy customization.$q$, $q$Administrators experience Service Cloud as a highly configurable but administration-heavy platform: routing rules, entitlements, and automation are built declaratively rather than coded, which lowers the technical bar somewhat but still demands real Salesforce expertise to do well. Most organizations lean on in-house admins, partners, or AppExchange packages to fill gaps rather than building everything from scratch.$q$, $q$For the broader business, the payoff is a unified customer record that support, sales, and marketing all read from, plus reporting that rolls support metrics up alongside pipeline and campaign data. That integration is Service Cloud's core differentiator, and it's most visible once an organization has invested the time to configure the platform around its own service processes.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ad6b4961-5c42-461f-8aa7-a80fba6f7c50', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
