INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Broken link and error detection$q$, $q$Identifies 4xx/5xx response codes, broken internal and external links, and server errors across a crawled site.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Redirect chain and loop auditing$q$, $q$Maps redirect chains and loops so migrations and cleanups can resolve them before they dilute link equity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$On-page metadata analysis$q$, $q$Reports on page titles, meta descriptions, headings, and word counts, flagging duplicates, missing, or over-length elements.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$JavaScript rendering$q$, $q$Renders JavaScript-driven pages so crawls reflect content generated by frameworks like React, Angular, or Vue.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Google Analytics and Search Console integration$q$, $q$Pulls in traffic, engagement, and search performance metrics alongside crawl data for combined analysis.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Custom extraction$q$, $q$Uses XPath, CSS selectors, or regular expressions to scrape specific page elements during a crawl.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$XML sitemap generation$q$, $q$Builds XML sitemaps directly from crawl data, respecting canonical and indexability rules.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Structured data validation$q$, $q$Extracts and validates schema.org structured data against Google's rich result requirements.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Crawl visualizations$q$, $q$Generates crawl and directory-tree diagrams to visualize site architecture and internal linking patterns.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Scheduled crawls$q$, $q$Automates recurring crawls on a set schedule and exports reports without manual re-runs.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Extremely detailed, granular data for technical SEO audits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Flat annual license fee instead of a recurring per-seat SaaS subscription$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Free tier available for smaller sites up to 500 URLs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Highly configurable, with custom extraction and third-party integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Long-established, widely trusted tool within the technical SEO community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Desktop-only application with no native web-based or mobile version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Steep learning curve for users unfamiliar with technical SEO concepts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Large crawls can be memory and CPU intensive on local hardware$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Dense, data-table-heavy interface can feel overwhelming to non-specialists$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Requires manual installation and updates rather than being cloud-hosted$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Is Screaming Frog SEO Spider free?$q$, $q$Yes, a free version is available, limited to crawling 500 URLs and without access to features like JavaScript rendering, scheduling, or saving crawls. A paid annual license removes the crawl limit and unlocks the full feature set.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$What platforms does it run on?$q$, $q$Screaming Frog SEO Spider is a desktop application available for Windows, Mac, and Linux.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Can it crawl JavaScript-rendered websites?$q$, $q$Yes, the paid version can render JavaScript so crawls capture content generated by frameworks such as React, Angular, or Vue rather than just raw HTML.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Does it integrate with Google Analytics and Search Console?$q$, $q$Yes, it can connect to Google Analytics, Google Search Console, and PageSpeed Insights to combine crawl data with traffic and performance metrics.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$How is it licensed and priced?$q$, $q$It uses a flat annual per-user license rather than a monthly subscription, with volume discounts available when purchasing multiple licenses at once.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Technical SEO audits$q$, $q$Crawl a site to surface broken links, redirect issues, duplicate or missing metadata, and indexability problems.$q$, $q$SEO agencies and in-house SEO teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Site migration and replatforming checks$q$, $q$Crawl before and after a migration or CMS change to confirm redirects, canonicals, and internal links carry over correctly.$q$, $q$Web developers and SEO consultants managing migrations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Content and duplicate content audits$q$, $q$Identify duplicate titles, meta descriptions, and thin content pages across large sites.$q$, $q$Content teams and site editors$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Site architecture and sitemap analysis$q$, $q$Visualize internal linking structure and generate XML sitemaps directly from crawl data.$q$, $q$Information architects and webmasters$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Crawl up to 500 URLs per crawl","Basic broken link and redirect checking","No saving of crawls","No JavaScript rendering or scheduling"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Paid License$q$, $q$$279/year (£199/year)$q$, $q$Annual$q$, $q$["Unlimited URL crawl limit","JavaScript rendering","Scheduled and automated crawls","Google Analytics, Search Console, and PageSpeed Insights integration","Custom extraction via XPath, CSS, or regex","Save and reopen crawls"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Screaming Frog SEO Spider is a desktop application that crawls websites the way a search engine bot would, pulling back URLs, internal and external links, images, CSS, scripts, response codes, and on-page metadata into a single sortable interface. It is built specifically for technical SEO diagnostics rather than general marketing reporting.$q$, $q$The tool is developed by Screaming Frog, a search marketing agency based in Henley-on-Thames, Oxfordshire, UK, founded in 2010. The SEO Spider crawler grew out of the agency's own auditing needs and has since become one of the most widely referenced crawling tools in the technical SEO community.$q$, $q$Unlike most modern SEO platforms, it runs locally on the user's own machine and is licensed with a flat annual fee rather than a recurring SaaS subscription. A free version exists with a 500 URL per crawl cap, while a paid license removes that limit and unlocks features such as JavaScript rendering, scheduling, and third-party integrations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$who-screaming-frog-is-for$q$, $q$Who Screaming Frog Is For$q$, 2, ARRAY[$q$SEO consultants and agencies running technical audits are the core audience. The Spider surfaces the kind of granular, page-by-page detail — broken links, duplicate titles, thin content, redirect chains — that underpins most technical SEO deliverables and client reports.$q$, $q$In-house SEO and web teams also rely on it heavily during site migrations, replatforming projects, or CMS changes, where confirming that redirects, canonical tags, and internal links carry over correctly is essential to protecting existing search rankings.$q$, $q$Freelancers and small businesses managing modest-sized websites can get real value from the free tier alone, since many smaller sites fall comfortably under the 500 URL crawl limit without ever needing a paid license.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Marketers who want an out-of-the-box dashboard with plain-language recommendations rather than raw crawl data may find the Spider overwhelming. It presents information for someone who already understands technical SEO concepts, not a simplified scorecard for non-specialists.$q$, $q$Teams that need a shared, always-on cloud crawler accessible to multiple stakeholders without installing desktop software will find the model a mismatch, since each license runs locally on one user's machine rather than through a hosted, multi-user dashboard.$q$, $q$Organizations crawling extremely large sites on modest hardware should also be cautious, since crawl performance and memory usage scale with local machine resources rather than elastic cloud infrastructure.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, the Spider crawls a site's URL structure and reports response codes, redirect chains, broken links, page titles, meta descriptions, headings, and directives like robots.txt and meta robots, all viewable and filterable in bulk.$q$, $q$It supports rendering JavaScript-heavy pages built with frameworks like React or Angular, so crawls reflect what a modern browser (and modern search engine) actually sees, and it can connect to Google Analytics, Google Search Console, and PageSpeed Insights to enrich crawl data with performance and traffic context.$q$, $q$Beyond crawling, it offers custom extraction via CSS, XPath, or regex, visualizations such as crawl and directory-tree diagrams, structured data validation, and XML sitemap generation, giving practitioners a broad technical SEO toolkit inside one application.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$the-screaming-frog-experience$q$, $q$The Screaming Frog Experience$q$, 2, ARRAY[$q$The interface is dense by design: tabbed data tables, extensive filters, and export options dominate the screen rather than polished charts. For practitioners who know what they're looking for, this density is an asset, letting them slice large data sets quickly.$q$, $q$New users typically face a learning curve, since the tool assumes familiarity with concepts like canonicalization, hreflang, and redirect logic. Screaming Frog's own documentation and blog content help bridge that gap, but there isn't much in the way of guided onboarding inside the app itself.$q$, $q$Overall, it feels like a specialist instrument rather than a polished all-in-one suite — unglamorous, occasionally resource-hungry on very large crawls, but dependable enough that it remains a staple in many technical SEO workflows.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
