INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Keyword Rank Tracker$q$, $q$Tracks daily keyword positions across Google, Bing, and other search engines, segmented by device, location, and search engine.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Keyword Research Tool$q$, $q$Surfaces search volume, keyword difficulty, and keyword grouping suggestions to build out content and campaign targeting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Website Audit$q$, $q$Crawls a site to score technical and on-page SEO health, with scheduled recrawls to monitor changes over time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Backlink Checker and Monitoring$q$, $q$Tracks a domain's backlink profile, flags potentially toxic links, and monitors new and lost links over time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Competitive Research$q$, $q$Compares visibility, estimated traffic, and keyword overlap against competitor domains.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$On-Page SEO Checker$q$, $q$Gives page-level optimization recommendations based on target keywords and current page content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$White-Label Reporting$q$, $q$Lets agencies generate client-branded PDF reports and dashboards without SE Ranking's own branding.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$AI Visibility Tracking$q$, $q$Monitors how a brand or domain appears in AI-generated answers and chat-based search experiences.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$API and MCP Access$q$, $q$Provides programmatic access to SE Ranking data for integration into external workflows or AI assistants.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Multi-Seat Project Management$q$, $q$Organizes tracked domains into projects with manager seats for coordinating work across client accounts.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Wide range of SEO tools bundled into a single platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Generally lower cost than comparable suites like Ahrefs or Semrush$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$White-label reporting well suited to agencies managing client accounts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Daily rank tracking with flexible device and location segmentation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$14-day free trial with no credit card required to test the platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Backlink index and historical data can be thinner than larger competitors in some markets$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Several higher-value features are sold as separate paid add-ons rather than included by default$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Interface can feel dense for new users given the number of modules and settings$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$No permanent free plan, only a time-limited trial$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Keyword and API credit limits scale with plan tier, which can require upgrading for larger sites$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$What is SE Ranking used for?$q$, $q$SE Ranking is used for day-to-day SEO work, including tracking keyword rankings, researching keywords, running technical site audits, monitoring backlinks, and analyzing competitors from a single dashboard.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Does SE Ranking offer a free plan?$q$, $q$SE Ranking does not offer a permanent free plan. Instead, it offers a 14-day free trial with core functionality that does not require a credit card to start.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$How is SE Ranking priced?$q$, $q$SE Ranking uses tiered monthly or annual subscription plans, with annual billing typically discounted compared to paying month to month. Some features, like white-label agency tools, AI visibility tracking, and expanded API access, are available as paid add-ons.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Is SE Ranking good for agencies?$q$, $q$Yes, SE Ranking includes white-label reporting, multi-seat project management, and client-friendly dashboards, which are features commonly used by agencies managing SEO for multiple client websites.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$How does SE Ranking compare to tools like Ahrefs or Semrush?$q$, $q$SE Ranking generally costs less than Ahrefs or Semrush and covers similar core workflows, though its backlink and keyword databases can be less extensive in certain markets, which may matter for heavy link-building or highly competitive research.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Daily Rank Tracking$q$, $q$Monitor keyword positions across search engines, devices, and locations to measure the impact of SEO efforts over time.$q$, $q$In-house SEO specialists and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Technical Site Audits$q$, $q$Run scheduled crawls to catch technical SEO issues, broken links, and on-page problems before they affect rankings.$q$, $q$Web developers and technical SEO teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$White-Label Client Reporting$q$, $q$Generate branded reports and dashboards to present SEO progress to clients without exposing the underlying tool.$q$, $q$SEO agencies managing multiple client accounts$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Backlink Profile Monitoring$q$, $q$Track new and lost backlinks and identify potentially toxic links that may need to be disavowed.$q$, $q$Link-building specialists and site owners$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Core$q$, $q$$129/month (or $103.20/month billed annually)$q$, $q$Monthly or annual$q$, $q$["10 projects, 1 manager seat","2,000 tracked keyword positions and 100 AI prompts per day","250k audit pages per month","25K API credits with MCP access","Rank tracking, keyword research, and website audit tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Growth$q$, $q$$279/month (or $223.20/month billed annually)$q$, $q$Monthly or annual$q$, $q$["30 projects, 3 manager seats","5,000 tracked keyword positions and 250 AI prompts per day","2M audit pages per month","100K API credits with MCP access","All-time historical data and collaboration tools for teams"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, $q$["Tailored project, seat, and keyword limits","Expanded API access","Custom terms for large teams and agencies","Dedicated support for high-volume usage"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SE Ranking is a cloud-based, all-in-one SEO platform founded in 2013 that combines keyword rank tracking, keyword research, technical site audits, backlink monitoring, and competitor analysis in a single dashboard. It has grown into one of the more widely used mid-market SEO suites, positioning itself as a lower-cost alternative to Ahrefs and Semrush while still covering most of the same core workflows agencies and marketers rely on day to day.$q$, $q$The platform tracks keyword positions across Google, Bing, Yahoo, and other search engines in a large number of countries, refreshing data daily and letting users segment results by device, location, and search engine. Beyond tracking, it layers in a keyword research module, an on-page and technical audit crawler, a backlink index with toxicity scoring, and white-label reporting aimed squarely at agencies managing multiple client accounts.$q$, $q$More recently, SE Ranking has added AI-focused features, including tools that monitor how brands appear in AI-generated answers and chat-based search experiences, alongside an API and MCP (Model Context Protocol) integration for pulling SEO data into external workflows or AI assistants. Pricing runs on tiered monthly or annual subscriptions with a 14-day free trial rather than a permanent free plan, and the company markets itself as a practical, budget-conscious option for teams that would otherwise be priced out of the larger enterprise SEO suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$who-se-ranking-is-for$q$, $q$Who SE Ranking Is For$q$, 2, ARRAY[$q$SE Ranking is built for SEO agencies, freelance consultants, and in-house marketing teams that need a full SEO toolkit without paying enterprise-level prices. Its white-label reporting, client management features, and manager-seat structure make it particularly well suited to agencies that track rankings and run audits for many client sites at once.$q$, $q$Small and midsize businesses that want to manage SEO in-house also fit the profile well, since the entry-level plan covers rank tracking, keyword research, and site audits at a price point well below comparable competitors. Content teams and bloggers can use the keyword research and on-page tools to plan and optimize pages without needing a dedicated SEO specialist on staff.$q$, $q$Teams beginning to experiment with AI search visibility - tracking how a brand shows up in AI-generated answers - may also find value in SE Ranking's newer AI monitoring features, since these are bundled or offered as an add-on rather than requiring a separate specialized tool. Marketing consultants who juggle several small clients often appreciate being able to run rank tracking, audits, and reporting from one login instead of stitching together several point solutions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Enterprises and large in-house SEO teams that depend on the largest possible backlink index or the deepest historical keyword databases may find SE Ranking's data coverage thinner than Ahrefs or Semrush in some markets, which can matter for link-building-heavy strategies or highly competitive niches.$q$, $q$Teams that want every advanced capability bundled into one flat price should also be cautious, since SE Ranking sells some higher-value features, such as its agency add-on, AI search add-on, and expanded API access, as separate paid extras rather than including them by default in the base plans.$q$, $q$Users who prioritize a minimalist, highly polished interface over feature breadth may find the platform's dashboard dense, with many modules and settings visible at once; this can create a steeper learning curve for solo users or those who only need one or two core functions rather than the full suite. Anyone looking for a single-purpose tool, such as a lightweight rank checker with nothing else attached, may also find SE Ranking more platform than they actually need.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, SE Ranking offers keyword rank tracking across search engines and devices, keyword research with volume and difficulty data, and a website audit crawler that scores technical and on-page health and can be scheduled to run automatically. A backlink checker tracks link profiles over time and flags potentially toxic links for disavow review.$q$, $q$Competitive research tools let users compare visibility, traffic estimates, and keyword overlap against competitors, while an on-page SEO checker gives page-by-page optimization recommendations. Agencies get white-label reporting and branded dashboards, plus multi-seat project management for coordinating work across client accounts.$q$, $q$Newer additions include AI visibility tracking for monitoring brand mentions in AI-generated answers, and an API with MCP support for feeding SE Ranking data into external tools or AI assistants. These features are organized around projects, so each tracked website gets its own dashboard combining rankings, audits, backlinks, and competitor data in one place, which makes it easier to move between reporting, research, and troubleshooting without switching tools entirely.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', $q$the-se-ranking-experience$q$, $q$The SE Ranking Experience$q$, 2, ARRAY[$q$Getting started typically involves creating a project for a domain, adding target keywords, and letting the platform run its first audit and ranking check, which populate the dashboard within a day or so. The interface groups tools into clear sections, such as the rank tracker, research, audit, and backlinks, though the sheer number of settings and filters can feel like a lot to absorb during the first few sessions.$q$, $q$Reports and data views are generally clear and exportable, and the white-label option lets agencies present client-branded reports without SE Ranking's own name attached, a detail that matters for agencies competing on presentation. Data refresh schedules and crawl limits are tied to the plan tier, so day-to-day usage feels responsive as long as a team stays within its project and keyword allowances.$q$, $q$Support is available through live chat and a help center, and users converting from the 14-day trial can typically carry their project setup over into a paid plan without starting from scratch. Overall, the experience favors teams that want one dashboard for most SEO tasks over a collection of specialized single-purpose tools, trading some interface polish for breadth of functionality and a lower overall subscription cost.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
