INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fd5e3d2c-6ddc-4750-8bd5-ba653068f181', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Merge PDFs$q$, $q$Combine multiple PDF files and images into a single document with control over page order.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Split and Extract$q$, $q$Split a PDF by page ranges, bookmarks, file size, or text, or extract and delete specific pages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$PDF Editor$q$, $q$Add or edit text, images, links, shapes, and whiteout directly on existing PDF pages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Fill and Sign$q$, $q$Fill out PDF forms and add signatures for lightweight approval and sign-off workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Format Conversion$q$, $q$Convert PDFs to Word, Excel, PowerPoint, JPG, and text, and convert Word, JPG, or HTML files into PDF.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Compression$q$, $q$Reduce PDF file size for easier sharing and storage while aiming to preserve visual quality.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$OCR$q$, $q$Turn scanned or image-based PDF pages into searchable, selectable, and editable text.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Document Security$q$, $q$Add or remove passwords and permissions, apply watermarks, redact content, and flatten forms.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Desktop Application$q$, $q$An offline Mac, Windows, and Linux app for processing PDFs without uploading files to a server.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Free tier requires no account signup for basic, occasional PDF tasks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Broad toolset of 30-plus features covers most common PDF needs in one place$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Uploaded files are stated to be deleted from servers after processing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Optional offline desktop app for Mac, Windows, and Linux$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Simple, uncluttered interface that is easy to pick up without training$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Free plan enforces daily task, file size, and page limits$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$No dedicated iOS or Android mobile apps$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Limited collaboration or team-workflow features compared to full document-management platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$No public developer API for programmatic PDF processing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Regular or high-volume use effectively requires a paid subscription$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Is Sejda PDF free to use?$q$, $q$Yes, Sejda offers a free tier that supports a limited number of tasks per day along with file-size and page limits, and it does not require creating an account. Paid Web and Desktop+Web plans remove these limits.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Do I need to create an account to use Sejda?$q$, $q$No, most core tools on the free tier can be used directly from the website without signing up. An account becomes relevant when subscribing to a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Is it safe to upload sensitive PDFs to Sejda?$q$, $q$Sejda states that uploaded files are transferred over an encrypted connection and deleted from its servers after processing. Users who prefer not to upload files at all can use the offline desktop application instead.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Does Sejda have a desktop application?$q$, $q$Yes, Sejda offers a desktop app compatible with Mac, Windows, and Linux that processes files locally, which is included with the Desktop+Web annual plan.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Can Sejda edit scanned or image-based PDFs?$q$, $q$Yes, Sejda includes OCR functionality that converts scanned or image-based PDF pages into searchable and editable text, with the number of OCR pages depending on the plan.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Filling and signing contracts$q$, $q$Quickly fill out PDF forms and add a signature to agreements or contracts without printing and scanning.$q$, $q$Freelancers and small-business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Converting scanned documents to editable text$q$, $q$Use OCR to turn scanned or photographed pages into searchable, editable text for reuse or citation.$q$, $q$Students and researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Organizing multi-file document sets$q$, $q$Merge, split, and reorder large batches of PDFs and scanned files into a single organized document.$q$, $q$Administrative and office staff$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Securing sensitive documents$q$, $q$Password-protect, redact, or watermark confidential files such as HR records or legal documents before sharing.$q$, $q$HR and legal professionals$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Limited tasks per day","File size and page limits","No signup required","Basic OCR"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Web Week Pass$q$, $q$~$5-6 per user$q$, $q$One-time (7 days)$q$, $q$["7 days of access to Sejda Web","Unlimited documents, no page or hourly limits","OCR up to 100 pages","Volume discount for 10+ users"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Web Monthly$q$, $q$$7.50 per user$q$, $q$Monthly$q$, $q$["Access to Sejda Web","Unlimited documents, no page or hourly limits","Processing multiple files at once","Up to 21 minutes processing time per task","File uploads up to 500MB"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$Desktop+Web Annual$q$, $q$$63-71 per user$q$, $q$Yearly$q$, $q$["Access to Sejda Web","A year of access to Sejda Desktop","Unlimited documents, no page or hourly limits","OCR up to 100 pages","Email support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sejda is a PDF editing and management platform that has been operating since 2010, built around a simple premise: most people need to merge, split, edit, or convert a PDF only occasionally, and shouldn't have to install heavyweight desktop software to do it. The company, based in Amsterdam, Netherlands, runs a browser-based service at sejda.com alongside an optional desktop application for Mac, Windows, and Linux.$q$, $q$The product covers more than 30 discrete PDF tools, spanning document assembly (merge, split, extract, delete, reorder pages), content editing (add text, images, links, shapes, and signatures), format conversion (PDF to and from Word, Excel, PowerPoint, JPG, and HTML), and document security (password protection, encryption, watermarking, and redaction). OCR is also built in, letting scanned or image-based PDFs be searched and edited.$q$, $q$Sejda operates on a freemium model: a no-signup-required free tier handles light, occasional use within daily task and file-size limits, while paid Web and Desktop+Web plans remove those limits and add features like multi-file batch processing and longer processing time per task. This structure has made it a widely used utility for individuals and small teams handling routine PDF work rather than large-scale document management.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$who-sejda-pdf-is-for$q$, $q$Who Sejda PDF Is For$q$, 2, ARRAY[$q$Sejda suits freelancers, students, and small-business owners who need to handle PDFs occasionally but don't want to buy or learn a full desktop suite. Tasks like filling out a form, merging a handful of scanned receipts, or converting a contract to Word are exactly the kind of one-off jobs the free tier is designed to cover without requiring an account.$q$, $q$It also works well for administrative and office staff who process moderate volumes of paperwork, such as HR documents, invoices, or client contracts, and want a single web tool that covers merging, editing, e-signatures, and conversion rather than juggling several single-purpose apps. Because file uploads are processed and then deleted from Sejda's servers, it can be a reasonable choice for anyone who wants to avoid installing unfamiliar software on a work machine.$q$, $q$Users who occasionally need OCR to make an old scanned document searchable, or who need to quickly redact or password-protect a sensitive file before sending it, are also a good fit. The paid plans extend the same simple workflow to slightly heavier, recurring use without introducing the complexity of enterprise document-management software.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large organizations that need a full document-management or workflow-automation platform, with audit trails, granular permissions, and deep integrations into content management systems, will likely find Sejda too lightweight. It is built as a focused PDF utility, not a document lifecycle or collaboration suite.$q$, $q$Teams that depend on programmatic access, such as automating PDF generation or conversion from within their own applications, may also be limited, since Sejda's public offering is centered on interactive web and desktop use rather than a developer API. Businesses whose workflows depend on mobile-first PDF editing should note that Sejda does not offer dedicated iOS or Android apps, relying instead on a browser or desktop client.$q$, $q$Heavy daily users who process large volumes of confidential PDFs may also want to weigh the free tier's daily task and page limits against a paid subscription early, since the free plan is intentionally scoped for occasional rather than continuous use.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Sejda offers document assembly tools: merging multiple PDFs and images into a single file, splitting a document by page ranges, bookmarks, size, or text, and extracting or deleting specific pages. Its editor allows users to add or modify text, images, links, and shapes directly on a PDF page, plus fill out forms and add signatures for lightweight sign-off workflows.$q$, $q$Conversion is a major part of the toolset, with support for turning PDFs into Word, Excel, PowerPoint, JPG, and plain text, and converting Word, JPG, or HTML files into PDF. Compression tools reduce file size for easier sharing or storage, and OCR processing (available up to a page limit that scales with the plan) converts scanned or image-based pages into searchable, selectable text.$q$, $q$Security and cleanup features round out the platform: adding or removing passwords and permissions, applying watermarks, flattening forms, redacting sensitive content, and deskewing scanned pages. The optional desktop application mirrors much of this functionality for offline use on Mac, Windows, and Linux, which matters for users who prefer not to upload sensitive files to a web server at all.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e533002d-957b-4a75-967f-c0c9aa3c3fc4', $q$the-sejda-pdf-experience$q$, $q$The Sejda PDF Experience$q$, 2, ARRAY[$q$The day-to-day experience of using Sejda is built around speed and minimal friction. Most tools are reachable directly from the homepage without an account, and a typical task (uploading a file, making an edit, and downloading the result) takes only a few clicks. The interface stays close to a single-purpose design, showing only the controls relevant to the tool in use rather than a crowded, all-in-one dashboard.$q$, $q$Files uploaded to the web app are processed on Sejda's servers over an encrypted connection and are stated to be deleted after processing, which is a meaningful consideration for anyone editing sensitive contracts, forms, or personal documents. Users who want to avoid any server upload at all can instead run the desktop application locally, trading a small amount of convenience for offline processing.$q$, $q$Where the experience can feel more constrained is around the free tier's daily task and file-size limits, which are enforced clearly rather than hidden, nudging frequent users toward a paid plan. Overall, the experience reads as a pragmatic, no-nonsense utility rather than a polished productivity suite, which fits its positioning as a fast way to solve a specific PDF problem rather than a place to manage a document library long-term.$q$]::text[], 4);
