INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$No-code storefront builder$q$, $q$Customize colors, fonts, and layout to launch a hosted store or embeddable buy button without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Digital product delivery$q$, $q$Securely host and deliver ebooks, music, software, presets, and other downloadable files with configurable limits.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Print-on-demand merchandise$q$, $q$Sell apparel and accessories that are produced and shipped by partner fulfillment facilities per order, with no inventory to manage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Subscription billing$q$, $q$Charge customers on a weekly, monthly, or yearly basis for ongoing access to digital content or memberships.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Built-in email marketing$q$, $q$Send newsletters and product updates to your customer list directly from the Sellfy dashboard.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Cart abandonment recovery$q$, $q$Automatically follow up with shoppers who leave items in their cart, available on Business plan and above.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Discount codes and upsells$q$, $q$Create promo codes and product upsell offers at checkout to increase average order value.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Affiliate marketing$q$, $q$Let affiliates promote products and earn commissions, available on Business and Premium plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Product embeds$q$, $q$Embed individual product buy buttons or widgets on an existing website or blog outside the Sellfy storefront.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$PayPal and Stripe checkout with 0% transaction fees$q$, $q$Accept payments through PayPal or Stripe without Sellfy taking an additional cut of each sale.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$No transaction fees on top of the subscription plan price$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Combines digital downloads, subscriptions, and print-on-demand merch in one dashboard$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Simple, no-code storefront setup that creators can launch quickly$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Built-in email marketing, discount codes, and upsell tools without extra add-ons$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$14-day free trial and a 30-day money-back guarantee for new upgrades$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$No permanent free plan for sellers who want to start at no cost$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Annual sales caps per plan mean high-growth stores must upgrade or negotiate custom pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Account dashboard is only available in English or Spanish, unlike the wider storefront language options$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Less catalog depth and third-party integration breadth than larger e-commerce platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Cart abandonment emails and affiliate marketing are locked behind the Business plan or higher$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Does Sellfy offer a free plan?$q$, $q$No, Sellfy does not currently offer a permanent free plan. It offers a 14-day free trial so sellers can test the platform before choosing a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Does Sellfy charge transaction fees?$q$, $q$Sellfy advertises 0% transaction fees across all of its plans; sellers only pay their monthly or annual subscription price plus standard fees from their payment processor, such as PayPal or Stripe.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Can I sell physical products on Sellfy, or only digital files?$q$, $q$Both. Sellfy supports digital downloads and subscriptions as well as print-on-demand physical merchandise like apparel and accessories, which are produced and shipped by partner fulfillment facilities.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$What happens if my store's sales exceed my plan's annual limit?$q$, $q$Each Sellfy plan (Starter, Business, Premium) includes an annual sales cap. Sellers who consistently exceed that cap need to upgrade to a higher plan, and stores exceeding the top Premium threshold can contact Sellfy about custom pricing.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$What languages does Sellfy support?$q$, $q$The customer-facing storefront and purchase emails can be set to English, Spanish, Portuguese, French, German, Italian, or Russian, or set to adjust automatically based on the customer's browser. The seller account dashboard itself is available in English or Spanish only.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Selling ebooks, guides, and courses$q$, $q$Authors and educators upload downloadable content, set pricing, and deliver files securely through a hosted store or embedded buy button.$q$, $q$Independent authors, coaches, and course creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Print-on-demand merch for creators$q$, $q$Creators add branded apparel and accessories to their store without holding inventory, since orders are produced and shipped by fulfillment partners.$q$, $q$YouTubers, artists, and podcasters building a merch line$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Selling music and digital audio$q$, $q$Musicians and producers sell tracks, albums, or sample packs directly to fans with secure file delivery and licensing controls.$q$, $q$Independent musicians and audio producers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Membership and subscription content$q$, $q$Creators charge recurring fees for ongoing access to digital content or communities, using Sellfy's subscription billing tools.$q$, $q$Creators building recurring, membership-based revenue$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Starter$q$, $q$$29/month ($22/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Up to $10,000 in annual sales","Unlimited digital, subscription, and print-on-demand products","Custom domain support","Email marketing up to 2,000 emails/month","Discount codes and product upselling","10GB max file size"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Business$q$, $q$$79/month ($59/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Up to $50,000 in annual sales","Everything in Starter","Cart abandonment emails","Affiliate marketing","Removal of Sellfy branding","Email marketing up to 10,000 emails/month","15GB max file size"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$Premium$q$, $q$$159/month ($119/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Up to $200,000 in annual sales","Everything in Business","Store and product migration assistance","Priority support","Email marketing up to 50,000 emails/month","20GB max file size"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sellfy is an e-commerce platform built for independent creators who want to sell digital products, physical merchandise, and subscriptions without stitching together a website, a payment processor, and a fulfillment partner on their own. Founded in 2011 and headquartered in Riga, Latvia, the company has grown from a simple digital-download storefront into a broader toolkit that also covers print-on-demand merch and recurring memberships, positioning itself as a lighter, creator-focused alternative to larger commerce platforms such as Shopify.$q$, $q$At its core, Sellfy lets sellers upload files such as ebooks, music, presets, templates, or software, set a price, and generate a hosted store or embeddable buy button in minutes. Beyond downloads, it layers in print-on-demand apparel and accessories that are produced and shipped by partner facilities when an order comes in, plus subscription billing for creators who want to charge on a weekly, monthly, or yearly basis for ongoing access to content. The goal across all of these product types is to let a single creator run a storefront without needing a developer, a warehouse, or a separate fulfillment vendor.$q$, $q$The platform runs on tiered monthly or annual subscription pricing rather than a percentage-based transaction fee, which Sellfy markets as a 0% transaction-fee model across every plan. There is no permanent free plan, but a 14-day free trial lets prospective sellers test the storefront builder, marketing tools, and checkout flow before committing to a paid tier, and a 30-day money-back guarantee softens the risk of a first upgrade.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$who-sellfy-is-for$q$, $q$Who Sellfy Is For$q$, 2, ARRAY[$q$Sellfy fits solo creators and small teams best: authors and course creators selling ebooks or guides, designers selling templates and presets, musicians selling tracks or sample packs, and educators packaging downloadable resources. These sellers typically want a store live quickly, without hiring a developer, and value having digital delivery, licensing, and file protection handled for them out of the box rather than configured from scratch.$q$, $q$It also suits creators who want to diversify beyond digital files into physical merchandise without holding inventory. Because print-on-demand production and shipping are handled by Sellfy's fulfillment network, a YouTuber, artist, or podcaster can add branded apparel or accessories to an existing digital storefront with minimal added operational work, and without pre-purchasing stock or managing a warehouse.$q$, $q$Finally, Sellfy appeals to creators building recurring revenue through memberships or subscription content, and to anyone who wants their marketing (email campaigns, discount codes, upsells) managed inside the same dashboard as their storefront rather than through a separate suite of disconnected tools. Sellers just getting started, or those consolidating several smaller tools into one account, tend to get the most value from this bundled approach.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Larger retailers and multi-channel sellers who need deep inventory management, multi-warehouse logistics, or native integrations with marketplaces like Amazon or Etsy will likely find Sellfy too limited. Its feature set is intentionally narrow compared to full commerce platforms, so complex catalogs or high-SKU physical retail operations are not its strength, and teams outgrowing a simple product catalog should look elsewhere.$q$, $q$Businesses that need extensive customization, such as a fully headless storefront, custom checkout logic, or deep API-driven workflows, may also outgrow Sellfy quickly, since its store builder favors simplicity and speed over granular developer control. Teams with in-house engineering resources who want full control over the buying experience will likely hit the platform's limits sooner than solo creators.$q$, $q$High-volume sellers should also weigh the plan-based annual sales caps built into Sellfy's pricing tiers. Once a store consistently exceeds the ceiling on its current plan, it must upgrade or contact Sellfy for custom pricing, which can make cost less predictable for fast-scaling businesses than a flat percentage-fee model that simply scales with revenue automatically.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Sellfy's storefront builder lets sellers customize colors, fonts, and layout without writing code, and stores can also be embedded as buy buttons or product widgets on an existing website or blog. Digital file delivery includes secure hosting, download limits, and support for large file sizes that scale with the chosen plan, so the underlying infrastructure grows alongside the seller's catalog.$q$, $q$Print-on-demand is built directly into the same dashboard, covering apparel and accessories that are produced and shipped by partner facilities when a customer places an order, so sellers don't manage physical inventory. Subscription billing lets creators charge recurring fees for access to content or memberships, and built-in email marketing supports newsletters, product announcements, and cart-abandonment recovery on higher-tier plans.$q$, $q$Additional marketing tools include discount codes, product upselling, and an affiliate marketing option on the Business and Premium plans, while checkout supports both PayPal and Stripe with no added transaction fee from Sellfy itself. Basic store analytics round out the toolkit so sellers can track sales, orders, and customer activity from the same dashboard used to manage products and campaigns.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c936aee7-ae75-49ba-bdd8-c809f3dbe535', $q$the-sellfy-experience$q$, $q$The Sellfy Experience$q$, 2, ARRAY[$q$Setting up a Sellfy store is generally fast: creators pick a plan, upload products, apply a storefront theme, and connect a payment processor without needing technical setup. This straightforward onboarding is one of the platform's most consistently cited strengths among creators comparing it to heavier e-commerce systems that require more configuration before a first sale can happen.$q$, $q$Day-to-day store management happens through a single dashboard covering products, orders, marketing campaigns, and basic analytics, and the account dashboard itself is available in English or Spanish. The customer-facing storefront and purchase emails support a wider set of languages, including French, German, Italian, Portuguese, and Russian, or can switch automatically based on a shopper's browser settings, which matters for creators selling to an international audience.$q$, $q$Support is delivered primarily through email and a self-serve help center, with priority support and store or product migration assistance reserved for the higher-tier Premium plan. Overall, the experience favors sellers who want a dependable, no-frills tool for turning digital and print-on-demand products into recurring income rather than a highly configurable enterprise commerce platform, and reviewers generally describe the learning curve as short.$q$]::text[], 4);
